import json

# Reset state to ensure invoice IDs are clean
tools.call("/system/reset_state")

# Create invoices using the explicit path-based call strategy to avoid method binding confusion
def create_inv(client, items, days):
    payload = {"client_name": client, "items": items, "due_days": days}
    return json.loads(tools.call("/accounting/create_invoice", payload))

res1 = create_inv('StartupX', [{'description': 'Development', 'quantity': 60, 'price': 175}], 30)
res2 = create_inv('RetailCo', [{'description': 'Consulting', 'quantity': 40, 'price': 200}], 45)
res3 = create_inv('TechGiant', [{'description': 'Design', 'quantity': 80, 'price': 150}, {'description': 'Testing', 'quantity': 20, 'price': 100}], 30)

def get_id(resp):
    return resp.get('invoice_id') or resp.get('id')

id1, id2, id3 = get_id(res1), get_id(res2), get_id(res3)

# Update statuses and handle payments
invoices_to_process = [id1, id2, id3]
for i_id in invoices_to_process:
    if i_id:
        tools.update_invoice_status(i_id, 'sent')

if id1: tools.record_partial_payment(id1, 7000)
if id2: tools.update_invoice_status(id2, 'paid')
if id3: tools.record_partial_payment(id3, 10000)

# Final report
all_invoices = json.loads(tools.get_invoices())
report = []
total_owing = 0
total_inc = 0

for inv in all_invoices:
    amt = float(inv.get('amount', 0))
    paid = float(inv.get('paid', 0))
    rem = amt - paid
    total_owing += rem
    total_inc += paid

    report.append({
        'client': inv.get('client_name'),
        'status': inv.get('status'),
        'total': amt,
        'paid': paid,
        'remaining': rem
    })

result = json.dumps({
    'invoice_summary': report,
    'total_receivables': total_owing,
    'total_income': total_inc,
    'follow_up': [inv['client_name'] for inv in all_invoices if (float(inv.get('amount', 0)) - float(inv.get('paid', 0))) > 0]
}, indent=2)

